// src/pages/vendor/VendorPortal.jsx
import React, { useState } from 'react';
import { useApp } from '../../App';
import { Sidebar } from '../../components/Sidebar';
import { Badge, ComplaintCard } from '../../components/ComplaintCard';
import { KPI, NotifBanner, Modal, ModalHeader } from '../../components/UI';

const BTN = ({ children, onClick, color = '#1565C0', outline = false, small = false }) => (
  <button onClick={onClick} style={{
    padding: small ? '6px 12px' : '8px 15px', borderRadius: 9, fontSize: small ? '12px' : '13px', fontWeight: 600, cursor: 'pointer',
    background: outline ? '#fff' : color, color: outline ? color : '#fff',
    border: outline ? `1px solid ${color}` : 'none', transition: 'all .15s',
    display: 'inline-flex', alignItems: 'center', gap: 5, width: '100%', justifyContent: 'center'
  }}>{children}</button>
);

export default function VendorPortal() {
  const { complaints, updateComplaint } = useApp();
  const [tab, setTab] = useState('tasks');
  const [selectedCleanerTask, setSelectedCleanerTask] = useState(null);
  const [notif, setNotif] = useState(null);

  // Dynamic ground cleaners list
  const cleanerStaff = [
    { id: 'c1', name: 'Dinesh Rao' },
    { id: 'c2', name: 'Suresh Patil' },
    { id: 'c3', name: 'Ramesh Kumar' }
  ];

  const handleAction = async (id, status) => {
    await updateComplaint(id, { status });
    const msgs = { ACCEPTED: 'Task accepted! Please assign a cleaner now.' };
    setNotif(msgs[status] || 'Status updated successfully');
  };

  const handleAssignCleaner = async (complaintId, cleaner) => {
    await updateComplaint(complaintId, {
      status: 'ASSIGNED_TO_CLEANER',
      assignedTo: cleaner.name,
      cleanerStatus: 'ASSIGNED'
    });
    setSelectedCleanerTask(null);
    setNotif(`Task assigned to ${cleaner.name} successfully!`);
  };

  const handleApproveClean = async (id) => {
    await updateComplaint(id, { 
      status: 'COMPLETED', 
      cleanerStatus: 'DONE',
      resolvedAt: new Date() 
    });
    setNotif("Verification Approved! Task cataloged as Completed.");
  };

  // Active pipelines processing filter
  const filteredTasks = complaints.filter(c => {
    if (tab === 'tasks') return !['COMPLETED', 'REJECTED'].includes(c.status);
    if (tab === 'done') return c.status === 'COMPLETED';
    return true;
  });

  return (
    <div style={{ display: 'flex', height: '100vh', fontFamily: 'system-ui,sans-serif', overflow: 'hidden' }}>
      <Sidebar 
        title="Express Travel" 
        subtitle="Vendor Engine" 
        navItems={[
          { key: 'tasks', icon: '📋', label: 'Tasks Panel', count: complaints.filter(c => ['NEW', 'ACCEPTED', 'ASSIGNED_TO_CLEANER', 'CLEANED_BY_FORCE'].includes(c.status)).length },
          { key: 'done', icon: '✅', label: 'Completed History' }
        ]} 
        activeTab={tab} 
        onTabChange={setTab}
        footerUser={{ initials: 'RK', name: 'Rajesh Kumar', role: 'Vendor Head', avatarColor: '#1565C0' }}
      />
      
      <div style={{ flex: 1, overflowY: 'auto', background: '#F7F9FC', padding: 22 }}>
        <div style={{ fontSize: 18, fontWeight: 800, marginBottom: 14 }}>
          {tab === 'tasks' ? 'Live Operations Dashboard' : 'Archive Cleared History Logs'}
        </div>
        {notif && <NotifBanner msg={notif} type="green" onDone={() => setNotif(null)} />}

        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit,minmax(260px,1fr))', gap: 16 }}>
          {filteredTasks.map(c => (
            <ComplaintCard key={c.id} complaint={c} actions={
              <div style={{ width: '100%', marginTop: 6, display: 'flex', flexDirection: 'column', gap: 6 }}>
                
                {/* STAGE 1: Nayi report aane par Accept button */}
                {c.status === 'NEW' && (
                  <BTN onClick={() => handleAction(c.id, 'ACCEPTED')} color="#1565C0">✓ Accept Ticket</BTN>
                )}

                {/* STAGE 2: Accept hone ke baad Assign Cleaner option */}
                {c.status === 'ACCEPTED' && (
                  <BTN onClick={() => setSelectedCleanerTask(c)} color="#4527A0">📢 Assign Cleaner Force</BTN>
                )}

                {/* STAGE 3: Cleaner ke kaam chalne ke dauran status badge */}
                {c.status === 'ASSIGNED_TO_CLEANER' && (
                  <div style={{ background: '#E3F2FD', color: '#1565C0', padding: '8px 12px', borderRadius: 8, fontSize: '12px', fontWeight: 700, textAlign: 'center' }}>
                    🏃 En Route: {c.assignedTo || 'Ground Crew'}
                  </div>
                )}

                {/* STAGE 4: Cleaner ke image proof bhejne par Complete option verification window ke sath */}
                {c.status === 'CLEANED_BY_FORCE' && (
                  <div style={{ background: '#FFF3E0', padding: 10, borderRadius: 10, border: '1px solid #E65100', width: '100%' }}>
                    <div style={{ fontSize: '11px', fontWeight: 700, color: '#E65100', marginBottom: 6 }}>✨ Cleaner Proof Image Sent:</div>
                    {c.cleanerPhoto ? (
                      <img src={c.cleanerPhoto} alt="After Work Evidence" style={{ width: '100%', height: 110, objectFit: 'cover', borderRadius: 6, marginBottom: 8 }} />
                    ) : (
                      <div style={{ fontSize: '11px', color: '#7A8FA6', marginBottom: 4 }}>Loading captured photo string...</div>
                    )}
                    <BTN onClick={() => handleApproveClean(c.id)} color="#2E7D32">✓ Approve & Complete Task</BTN>
                  </div>
                )}
              </div>
            } />
          ))}
        </div>
      </div>

      {/* Cleaner Force Allocation Menu Popup Overlays */}
      {selectedCleanerTask && (
        <Modal onClose={() => setSelectedCleanerTask(null)}>
          <ModalHeader title="Select Operational Crew" sub={selectedCleanerTask.id} onClose={() => setSelectedCleanerTask(null)} />
          <div style={{ padding: '0 20px 20px' }}>
            <div style={{ fontSize: 13, marginBottom: 12, color: '#3D4F61' }}>Select a crew to deploy at <strong>{selectedCleanerTask.area}</strong>:</div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
              {cleanerStaff.map(cleaner => (
                <button key={cleaner.id} onClick={() => handleAssignCleaner(selectedCleanerTask.id, cleaner)} style={{ padding: '12px', background: '#F7F9FC', border: '1px solid #DDE3E9', borderRadius: 8, textAlign: 'left', fontWeight: 600, cursor: 'pointer', fontSize: '13px' }}
                  onMouseEnter={e => e.currentTarget.style.background = '#E3F2FD'}
                  onMouseLeave={e => e.currentTarget.style.background = '#F7F9FC'}>
                  🦺 {cleaner.name} (Active)
                </button>
              ))}
            </div>
          </div>
        </Modal>
      )}
    </div>
  );
}
